slides.codeSnippet:
struct ValueUser { var name = "Struct_User" }
class RefUser { var name = "Class_User" }

// Testing Struct (Photocopy)
var v1 = ValueUser()
var v2 = v1
v2.name = "CHANGED"
print("Struct Original Name: \(v1.name)") // Still Struct_User

// Testing Class (Shared Reference)
var c1 = RefUser()
var c2 = c1
c2.name = "CHANGED"
print("Class Original Name: \(c1.name)")  // CHANGED!
